    account: { accountId: "acct-nc3", name: "Cedar Strategic", tier: "enterprise", region: "NA" },
    contract: { contractId: "ctr-nc3", arrCents: 6_000_000, renewalDate: "2026-11-30", supportPlan: "gold" },
