    shipments: [{ shipmentId: "shp-nc3", orderValueCents: 2_000_000, slaDate: "2026-07-01T00:00:00.000Z", deliveredDate: null, status: "in_transit" }],
    regulatoryFlags: [{ flagId: "reg-nc3", type: "export-control", status: "open" }],
