      console.error("Usage: node scripts/benchmark-run.mjs --suite ast-bench-v2 --shape <shallow|moderate|deep> --lane <mongo|postgres> --agent <claude-code|codex> [--repeat N]");
      process.exit(1);
    }

    if (!suiteV2.shapes.includes(shape)) {
