 73	    const status = qualifies ? ESCALATION_STATUS : MONITOR_STATUS;
 74	    const riskSummary = `${signals.length} signals: ${signals.map((cat) => SIGNAL_NAME[cat]).join(", ")}`;
 75	
 76	    const ownerSet = new Set(signals.map((cat) => OWNER_FOR_CATEGORY[cat]));
 77	    const owners = qualifies ? OWNER_ORDER.filter((o) => ownerSet.has(o)) : [];
 78	    const topOwner = owners[0] || null;
 79	    const nextStep = qualifies ? `${topOwner} recovery review by 16:00` : "Continue standard monitoring.";
 80	
 81	    await client.query("DELETE FROM workflow_state");
 82	    await client.query("DELETE FROM owner_tasks");
 83	    await client.query("DELETE FROM customer_messages");
 84	    await client.query("DELETE FROM audit_events");
 85	
 86	    await client.query(
 87	      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
 88	      [requestId, accountId, doc.request?.title || "Strategic account rescue", status, nextStep, riskSummary]
 89	    );
 90	
 91	    const dueAt = new Date(now);
 92	    dueAt.setUTCHours(16, 0, 0, 0);
 93	    for (const owner of owners) {
 94	      await client.query(
 95	        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
 96	        [requestId, accountId, owner, `${owner} recovery review for ${doc.name}`, dueAt.toISOString(), "open"]
 97	      );
 98	    }
 99	
100	    if (qualifies) {
101	      const signalList = signals.map((cat) => SIGNAL_NAME[cat].toLowerCase()).join(", ");
102	      const body = `We are reaching out proactively regarding your account. Our team has identified several areas that require immediate attention, including ${signalList}. Dedicated recovery owners across the relevant teams have been assigned and will be in contact shortly to discuss next steps and work with you toward resolution. We appreciate your continued partnership and are committed to resolving these matters as quickly as possible.`;
103	      await client.query(
104	        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
105	        [requestId, accountId, body]
106	      );
107	    }
108	
109	    const event = qualifies
110	      ? `Escalation workflow initiated: ${riskSummary}. Recovery teams have been engaged.`
111	      : `Account review completed. No escalation required at this time.`;
112	    await client.query(
113	      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
114	      [requestId, accountId, event, now, true]
115	    );
116	  });
117	}
118	
119	if (import.meta.url === `file://${process.argv[1]}`) {
120	  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
121	}
